[FormEventHandler(formStr(BankAccountTrans), FormEventType::Initialized)]
public static void BankAccountTrans_OnInitialized(xFormRun sender, FormEventArgs e)
{

    FormDataSource bankAccountTrans_ds;
    FormGridControl overviewGrid;
    FormControl    clearingDateCtrl;
    ETGCanadaParameters etgParams;
    boolean isEnabled;

    //making readonly form editable
    sender.design().viewEditMode(ViewEditMode::Edit);

    // Get datasource
    bankAccountTrans_ds = sender.dataSource(formDataSourceStr(BankAccountTrans, BankAccountTrans));

    // Get parameter
    etgParams = ETGCanadaParameters::find();
    isEnabled = etgParams.EnableClearingDateReconciliation;

    bankAccountTrans_ds.allowEdit(true);
    allowEditFieldsOnFormDS_W(bankAccountTrans_ds, false);

    // Editability
    bankAccountTrans_ds.object(fieldNum(BankAccountTrans, ClearingDate)).allowEdit(isEnabled);

    clearingDateCtrl=sender.design().controlName(identifierStr(OverviewGrid_ClearingDate));

    clearingDateCtrl.visible(isEnabled);


}
